		if (aiGotIt) {
			gs.aiCorrect++;
			const aiPts = 100 * (question.difficulty === 'easy' ? 1 : question.difficulty === 'medium' ? 2 : 3);
			gs.aiScore += aiPts;
		}
		const youIcon = isCorrect ? 'OK' : 'X';
