		hint?.setProperties({ text: '---' });
	}
}

function useDoublePoints(): void {
	if (!gameRunning || feedbackShowing || !gs.hasDouble) return;
	gs.hasDouble = false;
	gs.doublePoints = 3;
	showToastMsg('DOUBLE POINTS — Next 3 correct = 2x!', 2);
