function setupScene(): void {
	const theme = THEMES[settingsState.themeIdx];
	const scene = worldRef.scene;

	// Background & Fog
	scene.background = new Color(theme.bg);
	scene.fog = new FogExp2(theme.fog, 0.04);

	// Lighting
	const ambient = new AmbientLight(0x222233, 0.6);
	scene.add(ambient);

	const dirLight = new DirectionalLight(0xffffff, 0.3);
	dirLight.position.set(5, 10, 5);
	scene.add(dirLight);

	for (let i = 0; i < 3; i++) {
		const pl = new PointLight(theme.primary, 0.5, 20);
		pl.position.set(
			(i - 1) * 6,
			3 + i * 0.5,
			-2 - i * 2,
		);
		scene.add(pl);
		sceneLights.push(pl);
	}

	// Floor & ceiling grids
	floorGrid = new GridHelper(40, 40, theme.primary, theme.secondary);
	scene.add(floorGrid);
	ceilGrid = new GridHelper(40, 40, theme.primary, theme.secondary);
	ceilGrid.position.y = 6;
	scene.add(ceilGrid);

	// Wireframe decorations
	const geos = [
		new OctahedronGeometry(0.3),
		new TorusGeometry(0.25, 0.08, 8, 12),
		new IcosahedronGeometry(0.25),
		new BoxGeometry(0.35, 0.35, 0.35),
		new SphereGeometry(0.2, 8, 6),
		new OctahedronGeometry(0.2),
		new TorusGeometry(0.2, 0.06, 6, 10),
		new IcosahedronGeometry(0.3),
	];

	for (let i = 0; i < 8; i++) {
		const mat = new LineBasicMaterial({ color: theme.primary, transparent: true, opacity: 0.4 });
		wireMats.push(mat);
		const edges = new EdgesGeometry(geos[i]);
		const lineSegs = new LineSegments(edges, mat);
		const g = new Group();
		g.add(lineSegs);
		const angle = (i / 8) * Math.PI * 2;
		const radius = 3 + Math.random() * 4;
		g.position.set(
			Math.cos(angle) * radius,
			1 + Math.random() * 4,
			Math.sin(angle) * radius - 3,
		);
		scene.add(g);
		wireframeGroups.push(g);
	}

	// Particles (250 pool)
	const count = 250;
	const positions = new Float32Array(count * 3);
	particleSpeeds = [];
	for (let i = 0; i < count; i++) {
		positions[i * 3] = (Math.random() - 0.5) * 30;
		positions[i * 3 + 1] = Math.random() * 6;
		positions[i * 3 + 2] = (Math.random() - 0.5) * 30;
		particleSpeeds.push(0.1 + Math.random() * 0.3);
	}
	particleGeo = new BufferGeometry();
	particleGeo.setAttribute('position', new Float32BufferAttribute(positions, 3));
	particleMat = new PointsMaterial({
		color: theme.primary,
		size: 0.06,
		transparent: true,
		opacity: 0.6,
		blending: AdditiveBlending,
		depthWrite: false,
	});
	const points = new Points(particleGeo, particleMat);
	scene.add(points);

	// Central floating platform (decorative)
	const platGeo = new BoxGeometry(1.6, 0.03, 0.8);
	const platEdges = new EdgesGeometry(platGeo);
	const platMat = new LineBasicMaterial({ color: theme.primary, transparent: true, opacity: 0.3 });
	wireMats.push(platMat);
	const platLines = new LineSegments(platEdges, platMat);
	platLines.position.set(0, 0.5, -1.3);
	scene.add(platLines);

	// Animated torus ring
	const ringGeo = new TorusGeometry(1.0, 0.04, 16, 48);
	const ringEdges = new EdgesGeometry(ringGeo);
	const ringMat = new LineBasicMaterial({ color: theme.primary, transparent: true, opacity: 0.5 });
	wireMats.push(ringMat);
	const ringLines = new LineSegments(ringEdges, ringMat);
	sceneRing = new Group();
	sceneRing.add(ringLines);
	sceneRing.position.set(0, 2.5, -3);
	scene.add(sceneRing);

	// Orbiting point lights (4)
	for (let i = 0; i < 4; i++) {
		const opl = new PointLight(theme.primary, 0.4, 15);
		scene.add(opl);
		orbitingLights.push(opl);
	}

	// Trail particle system (50 particles, initially hidden at Y=-100)
	const trailCount = 50;
	const trailPositions = new Float32Array(trailCount * 3);
	trailParticleSpeeds = [];
	for (let i = 0; i < trailCount; i++) {
		trailPositions[i * 3] = 0;
		trailPositions[i * 3 + 1] = -100;
		trailPositions[i * 3 + 2] = 0;
		trailParticleSpeeds.push({ vx: 0, vy: 0, vz: 0, life: 0 });
	}
	trailParticleGeo = new BufferGeometry();
	trailParticleGeo.setAttribute('position', new Float32BufferAttribute(trailPositions, 3));
	trailParticleMat = new PointsMaterial({
		color: 0xffcc00,
		size: 0.08,
		transparent: true,
		opacity: 0.8,
		blending: AdditiveBlending,
		depthWrite: false,
	});
	const trailPoints = new Points(trailParticleGeo, trailParticleMat);
	scene.add(trailPoints);
}

