	update(delta: number, time: number) {
		// ---- Countdown ----
		if (countdownActive) {
			countdownTimer -= delta;
			const d = docs['countdown'];
			if (d) {
				const num = Math.ceil(countdownTimer);
				const lbl = d.getElementById('lbl-count') as UIKit.Text;
				lbl?.setProperties({ text: num > 0 ? String(num) : 'GO!' });
			}
			if (countdownTimer <= -0.5) {
				countdownActive = false;
				beginPlay();
			}
			return; // Don't process other timers during countdown
		}

		// ---- Toast timer ----
		if (toastTimer > 0) {
			toastTimer -= delta;
			if (toastTimer <= 0) {
				hidePanel('toast');
			}
		}

		// ---- Achievement Notification timer ----
		if (achvNotifyTimer > 0) {
			achvNotifyTimer -= delta;
			if (achvNotifyTimer <= 0) {
				if (pendingAchievements.length > 0) {
					const achIdx = pendingAchievements.shift()!;
					const ach = ACHIEVEMENT_DEFS[achIdx];
					const d = docs['achvnotify'];
					if (d) {
						const titleLbl = d.getElementById('lbl-achv-title') as UIKit.Text;
						titleLbl?.setProperties({ text: 'ACHIEVEMENT UNLOCKED!' });
						const nameLbl = d.getElementById('lbl-achv-name') as UIKit.Text;
						nameLbl?.setProperties({ text: ach.name });
						const descLbl = d.getElementById('lbl-achv-desc') as UIKit.Text;
						descLbl?.setProperties({ text: ach.desc });
					}
					showPanel('achvnotify');
					achvNotifyTimer = 3.0; // Show for 3 seconds
				} else {
					hidePanel('achvnotify');
				}
			}
		}

		// ---- Feedback timer ----
		if (feedbackShowing) {
			feedbackTimer -= delta;
			if (feedbackTimer <= 0) {
				feedbackShowing = false;
				if (gs.mode === 'streak' && gs.combo === 0 && gs.totalAnswered > 0) {
					endGame();
				} else if (gs.mode === 'endless' && gs.lives <= 0) {
					endGame();
				} else {
					nextQuestion();
				}
			}
		}

		// ---- Game timer ----
		if (gameRunning && !gamePaused && !feedbackShowing) {
			gameElapsed += delta;

			if (gs.mode === 'speed') {
				speedModeTimer -= delta;
				if (speedModeTimer <= 0) {
					speedModeTimer = 0;
					endGame();
					return;
				}
				updateHUD();
			} else if (gs.mode !== 'practice' && gs.mode !== 'streak' && gs.mode !== 'endless') {
				if (!gs.timeFrozen) gs.timer -= delta;
				if (gs.timer <= 0) {
					gs.timer = 0;
					// Time ran out for this question — treat as wrong
					gs.totalAnswered++;
					gs.results[gs.currentIndex] = false;
					gs.combo = 0;
					gs.streak = 0;
					const question = gs.questions[gs.currentIndex];
					showToastMsg(`Time's up! Answer: ${question.answers[question.correct]}`, 1.5);
					feedbackShowing = true;
					feedbackTimer = 1.5;
				}
				updateHUD();
			}
		}

		// ---- Input ----
		if (gameRunning && !feedbackShowing) {
			const kb = this.world.input.keyboard;
			if (kb.getKeyDown('Digit1')) selectAnswer(0);
			if (kb.getKeyDown('Digit2')) selectAnswer(1);
			if (kb.getKeyDown('Digit3')) selectAnswer(2);
			if (kb.getKeyDown('Digit4')) selectAnswer(3);
			if (kb.getKeyDown('KeyF')) useFiftyFifty();
			if (kb.getKeyDown('KeyS')) useSkip();
			if (kb.getKeyDown('KeyH')) useHint();
			if (kb.getKeyDown('KeyD')) useDoublePoints();
			if (kb.getKeyDown('KeyT')) useTimeFreeze();
			if (kb.getKeyDown('Escape') || kb.getKeyDown('KeyP')) togglePause();

			const rightPad = this.world.input.xr.gamepads.right;
			if (rightPad?.getButtonDown(InputComponent.B_Button)) togglePause();
			if (rightPad?.getButtonDown(InputComponent.A_Button)) useDoublePoints();
		}

		// ---- HUD bounce recovery ----
		if (hudBounceTimer > 0) {
			hudBounceTimer -= delta;
			if (hudBounceTimer <= 0) {
				const hudOv = offsets['hud'];
				if (hudOv) {
					hudOv[1] = PANEL_CONFIGS['hud'].y;
				}
			}
		}

		// ---- Wrong answer flash recovery ----
		if (wrongFlashTimer > 0) {
			wrongFlashTimer -= delta;
			if (wrongFlashTimer <= 0) {
				const theme = THEMES[settingsState.themeIdx];
				for (const l of sceneLights) {
					l.color.setHex(theme.primary);
					l.intensity = 0.5;
				}
			}
		}

		// ---- Holographic panel float (menu panels only, not during gameplay) ----
		if (!gameRunning) {
			const menuPanels = ['title', 'modeselect', 'catpick', 'difficulty', 'achvlist', 'stats', 'settings', 'leaderboard', 'help', 'review', 'gameover'];
			let panelIndex = 0;
			for (const name of menuPanels) {
				const ov = offsets[name];
				const pc = PANEL_CONFIGS[name];
				if (ov && pc && ov[1] > -50) {
					ov[1] = pc.y + Math.sin(time * 0.8 + panelIndex * 0.5) * 0.001;
				}
				panelIndex++;
			}
		}

		// ---- Animate particles ----
		if (particleGeo) {
			const pos = particleGeo.getAttribute('position');
			if (pos) {
				for (let i = 0; i < particleSpeeds.length; i++) {
					let y = (pos as any).getY(i) + particleSpeeds[i] * delta;
					if (y > 6) y = -0.5;
					(pos as any).setY(i, y);
					// Performance: skip X oscillation for off-screen particles
					if (y > -10) {
						const x = (pos as any).getX(i) + Math.sin(time * 0.5 + i) * 0.002;
						(pos as any).setX(i, x);
					}
				}
				(pos as any).needsUpdate = true;
			}
		}

		// ---- Animate trail particles ----
		if (trailParticleGeo) {
			const tPos = trailParticleGeo.getAttribute('position');
			if (tPos) {
				let anyActive = false;
				for (let i = 0; i < trailParticleSpeeds.length; i++) {
					const sp = trailParticleSpeeds[i];
					if (sp.life > 0) {
						anyActive = true;
						sp.life -= delta;
						const cx = (tPos as any).getX(i) + sp.vx * delta;
						const cy = (tPos as any).getY(i) + sp.vy * delta;
						const cz = (tPos as any).getZ(i) + sp.vz * delta;
						(tPos as any).setXYZ(i, cx, cy, cz);
						if (sp.life <= 0) {
							(tPos as any).setY(i, -100);
						}
					}
				}
				if (anyActive) (tPos as any).needsUpdate = true;
			}
		}

		// ---- Animate wireframes (skip distant ones for performance) ----
		const wireSpeedMult = streakLevel === 2 ? 3 : streakLevel === 1 ? 2 : 1;
		for (let i = 0; i < wireframeGroups.length; i++) {
			const g = wireframeGroups[i];
			// Performance: skip wireframes beyond 15 units from camera
			const dx = g.position.x;
			const dy = g.position.y - 1.6;
			const dz = g.position.z;
			const distSq = dx * dx + dy * dy + dz * dz;
			if (distSq > 225) continue; // 15^2 = 225
